/**
 * NIP-19: bech32-encoded entities
 * Implements encoding and decoding of Nostr entities using bech32 format
 */

import { bech32 } from 'bech32';
import { hexToBytes, bytesToHex } from '@noble/hashes/utils.js';

const utf8Encoder = new TextEncoder();
const utf8Decoder = new TextDecoder();

export type Nip19DataType = 'npub' | 'nsec' | 'note' | 'nprofile' | 'nevent' | 'naddr' | 'nrelay';

const VALID_PREFIXES: Nip19DataType[] = ['npub', 'nsec', 'note', 'nprofile', 'nevent', 'naddr', 'nrelay'];

export interface Nip19Data {
  type: Nip19DataType;
  data: string;
  relays?: string[];
  author?: string;
  kind?: number;
  identifier?: string; // For naddr
}

// TLV type constants (NIP-19). SPECIAL is the primary value: a 32-byte hex
// pubkey/id for nprofile/nevent, or the UTF-8 d-tag identifier for naddr.
// NIP-19 defines no TLV type 4.
const TLV_TYPES = {
  SPECIAL: 0,   // Primary value (hex for nprofile/nevent; UTF-8 identifier for naddr)
  RELAY: 1,     // Relay URL (utf8)
  AUTHOR: 2,    // Author pubkey (32-byte hex)
  KIND: 3       // Event kind (uint32 big-endian)
} as const;

/**
 * Encode a public key as an npub
 * @param pubkey Public key in hex format
 * @returns bech32-encoded npub string
 * @throws {Error} If pubkey is invalid
 */
export function npubEncode(pubkey: string): string {
  validateHexString(pubkey, 64);
  const data = hexToBytes(pubkey);
  const words = bech32.toWords(data);
  return bech32.encode('npub', words, 1000);
}

/**
 * Encode a private key as an nsec
 * @param privkey Private key in hex format
 * @returns bech32-encoded nsec string
 * @throws {Error} If privkey is invalid
 */
export function nsecEncode(privkey: string): string {
  validateHexString(privkey, 64);
  const data = hexToBytes(privkey);
  const words = bech32.toWords(data);
  return bech32.encode('nsec', words, 1000);
}

/**
 * Encode an event ID as a note
 * @param eventId Event ID in hex format
 * @returns bech32-encoded note string
 * @throws {Error} If eventId is invalid
 */
export function noteEncode(eventId: string): string {
  validateHexString(eventId, 64);
  const data = hexToBytes(eventId);
  const words = bech32.toWords(data);
  return bech32.encode('note', words, 1000);
}

/**
 * Encode profile information
 * @param pubkey Public key in hex format
 * @param relays Optional relay URLs
 * @returns bech32-encoded nprofile string
 * @throws {Error} If pubkey is invalid or relays are malformed
 */
export function nprofileEncode(pubkey: string, relays?: string[]): string {
  validateHexString(pubkey, 64);
  if (relays) {
    relays.forEach(validateRelayUrl);
  }

  const data = encodeTLV({
    type: 'nprofile',
    data: pubkey,
    relays
  });
  return bech32.encode('nprofile', data, 1000);
}

/**
 * Encode event information
 * @param eventId Event ID in hex format
 * @param relays Optional relay URLs
 * @param author Optional author public key
 * @param kind Optional event kind
 * @returns bech32-encoded nevent string
 * @throws {Error} If parameters are invalid
 */
export function neventEncode(
  eventId: string,
  relays?: string[],
  author?: string,
  kind?: number
): string {
  validateHexString(eventId, 64);
  if (relays) {
    relays.forEach(validateRelayUrl);
  }
  if (author) {
    validateHexString(author, 64);
  }
  if (kind !== undefined && !Number.isInteger(kind)) {
    throw new Error('Invalid event kind');
  }

  const data = encodeTLV({
    type: 'nevent',
    data: eventId,
    relays,
    author,
    kind
  });
  return bech32.encode('nevent', data, 1000);
}

/**
 * Encode an address (NIP-33)
 * @param pubkey Author's public key
 * @param kind Event kind
 * @param identifier String identifier
 * @param relays Optional relay URLs
 * @returns bech32-encoded naddr string
 * @throws {Error} If parameters are invalid
 */
export function naddrEncode(
  pubkey: string,
  kind: number,
  identifier: string,
  relays?: string[]
): string {
  validateHexString(pubkey, 64);
  if (!Number.isInteger(kind)) {
    throw new Error('Invalid event kind');
  }
  if (!identifier) {
    throw new Error('Identifier is required');
  }
  if (relays) {
    relays.forEach(validateRelayUrl);
  }

  // NIP-19 naddr TLV: SPECIAL(0) = d-tag identifier (UTF-8), AUTHOR(2) = 32-byte
  // pubkey, KIND(3) = uint32 BE, RELAY(1) = relays. The identifier is the SPECIAL
  // value; the pubkey is the AUTHOR (there is no TLV type 4).
  const data = encodeTLV({
    type: 'naddr',
    data: identifier,
    author: pubkey,
    kind,
    relays
  });
  return bech32.encode('naddr', data, 1000);
}

/**
 * Encode a relay URL
 * @param url Relay URL
 * @returns bech32-encoded nrelay string
 * @throws {Error} If URL is invalid
 */
export function nrelayEncode(url: string): string {
  validateRelayUrl(url);
  const data = utf8Encoder.encode(url);
  const words = bech32.toWords(data);
  return bech32.encode('nrelay', words, 1000);
}

/**
 * Decode a bech32-encoded Nostr entity
 * @param str bech32-encoded string
 * @returns Decoded data with type and metadata
 * @throws {Error} If string is invalid or malformed
 */
export function decode(str: string): Nip19Data {
  if (!str.includes('1')) {
    throw new Error('Invalid bech32 string');
  }

  const prefix = str.split('1')[0].toLowerCase();
  if (!VALID_PREFIXES.includes(prefix as Nip19DataType)) {
    throw new Error('Unknown prefix');
  }

  try {
    const decoded = bech32.decode(str, 1000);
    const data = Uint8Array.from(bech32.fromWords(decoded.words));

    // For nrelay type
    let url: string;
    // For TLV types
    let decodedData: Nip19Data;

    switch (decoded.prefix) {
      case 'npub':
      case 'nsec':
      case 'note': {
        const hex = bytesToHex(data);
        validateHexString(hex, 64);
        return {
          type: decoded.prefix as Nip19DataType,
          data: hex
        };
      }
      case 'nrelay':
        url = utf8Decoder.decode(data);
        validateRelayUrl(url);
        return {
          type: 'nrelay',
          data: url
        };
      case 'nprofile':
      case 'nevent':
      case 'naddr':
        decodedData = decodeTLV(decoded.prefix as Nip19DataType, data);
        return decodedData;
      default:
        throw new Error('Unknown prefix');
    }
  } catch (error: unknown) {
    if (error instanceof Error) {
      throw error;
    }
    throw new Error('Invalid bech32 string');
  }
}

// Helper functions

function validateHexString(str: string, length?: number): void {
  if (!/^[0-9a-fA-F]+$/.test(str)) {
    throw new Error('Invalid hex string');
  }
  if (length && str.length !== length) {
    throw new Error(`Invalid hex string length (expected ${length})`);
  }
}

function validateRelayUrl(url: string): void {
  try {
    const parsed = new URL(url);
    if (!['ws:', 'wss:'].includes(parsed.protocol)) {
      throw new Error('Invalid relay URL protocol');
    }
  } catch {
    throw new Error('Invalid relay URL');
  }
}

function encodeTLV(data: Nip19Data): number[] {
  const result: number[] = [];
  const isNaddr = data.type === 'naddr';

  // Kind (type 3): event kind as uint32 big-endian
  if (data.kind !== undefined) {
    const kindBytes = new Uint8Array(4);
    new DataView(kindBytes.buffer).setUint32(0, data.kind, false);
    result.push(TLV_TYPES.KIND, kindBytes.length);
    result.push(...kindBytes);
  }

  // Author (type 2): author pubkey (32-byte hex)
  if (data.author) {
    const authorBytes = hexToBytes(data.author);
    result.push(TLV_TYPES.AUTHOR, authorBytes.length);
    result.push(...authorBytes);
  }

  // Relay (type 1): relay URLs (utf8)
  if (data.relays?.length) {
    for (const relay of data.relays) {
      const relayBytes = utf8Encoder.encode(relay);
      result.push(TLV_TYPES.RELAY, relayBytes.length);
      result.push(...relayBytes);
    }
  }

  // Special (type 0), emitted last: UTF-8 identifier for naddr, 32-byte hex
  // pubkey/id for nprofile/nevent. Per NIP-19 there is no separate TLV type 4;
  // the naddr d-tag identifier IS the SPECIAL value.
  const specialBytes = isNaddr
    ? utf8Encoder.encode(data.data)
    : hexToBytes(data.data);
  result.push(TLV_TYPES.SPECIAL, specialBytes.length);
  result.push(...specialBytes);

  return bech32.toWords(Uint8Array.from(result));
}

function decodeTLV(prefix: Nip19DataType, data: Uint8Array): Nip19Data {
  const isNaddr = prefix === 'naddr';
  const result: Nip19Data = {
    type: prefix,
    data: '',
    relays: []
  };

  let i = 0;
  // For relay type
  let relay: string;

  while (i < data.length) {
    const type = data[i];
    const length = data[i + 1];

    if (i + 2 + length > data.length) {
      throw new Error('Invalid TLV data');
    }

    const value = data.slice(i + 2, i + 2 + length);

    switch (type) {
      case TLV_TYPES.SPECIAL:
        if (isNaddr) {
          // For naddr, SPECIAL is the UTF-8 d-tag identifier, not hex.
          result.data = utf8Decoder.decode(value);
          result.identifier = result.data;
        } else {
          result.data = bytesToHex(value);
          validateHexString(result.data, 64);
        }
        break;
      case TLV_TYPES.RELAY:
        relay = utf8Decoder.decode(value);
        validateRelayUrl(relay);
        result.relays = result.relays || [];
        result.relays.push(relay);
        break;
      case TLV_TYPES.AUTHOR:
        result.author = bytesToHex(value);
        validateHexString(result.author, 64);
        break;
      case TLV_TYPES.KIND:
        result.kind = new DataView(value.buffer, value.byteOffset, value.byteLength).getUint32(0, false);
        break;
      default:
        // Skip unknown TLV types
        break;
    }

    i += 2 + length;
  }

  // naddr requires an author (pubkey) and kind per NIP-19.
  if (isNaddr && (!result.author || result.kind === undefined)) {
    throw new Error('Invalid naddr: missing author or kind');
  }

  return result;
}
